STDLIB_MODULES = {
    'os', 'sys', 'math', 'json', 're', 'datetime', 'collections',
    'itertools', 'functools', 'pathlib', 'typing', 'unittest',
    'random', 'string', 'io', 'csv', 'hashlib', 'logging',
    'argparse', 'subprocess', 'threading', 'socket', 'http',
    'urllib', 'email', 'abc', 'copy', 'time', 'calendar'
}

THIRD_PARTY_MODULES = {
    'numpy', 'pandas', 'requests', 'flask', 'django', 'pytest',
    'sqlalchemy', 'celery', 'redis', 'boto3', 'pillow', 'scipy',
    'matplotlib', 'seaborn', 'fastapi', 'pydantic'
}


def parse_import(import_str):
    parts = import_str.strip().split()
    result = {'module': '', 'alias': None, 'names': []}

    if parts[0] == 'from':
        result['module'] = parts[1]
        # skip 'import' at index 2
        names_part = ' '.join(parts[3:])
        names = [n.strip() for n in names_part.split(',')]
        cleaned = []
        i = 0
        while i < len(names):
            if i + 1 < len(names) and names[i + 1] == 'as':
                i += 1
                continue
            cleaned.append(names[i].split(' as ')[0].strip() if ' as ' in names[i] else names[i])
            i += 1
        result['names'] = cleaned
    elif parts[0] == 'import':
        result['module'] = parts[1]
        if 'as' in parts:
            as_idx = parts.index('as')
            result['alias'] = parts[as_idx + 1]

    return result


def is_valid_import(import_str):
    import re
    s = import_str.strip()
    identifier = r'[a-zA-Z_][a-zA-Z0-9_]*(\.[a-zA-Z_][a-zA-Z0-9_]*)*'
    patterns = [
        rf'^import\s+{identifier}$',
        rf'^import\s+{identifier}\s+as\s+{identifier}$',
        rf'^from\s+{identifier}\s+import\s+{identifier}(\s+as\s+{identifier})?(\s*,\s*{identifier}(\s+as\s+{identifier})?)*$'
    ]
    return any(re.match(p, s) for p in patterns)


def categorize_imports(import_lines):
    result = {'stdlib': [], 'third_party': [], 'local': []}
    for line in import_lines:
        parsed = parse_import(line)
        base_module = parsed['module'].split('.')[0]
        if base_module in STDLIB_MODULES:
            result['stdlib'].append(line)
        elif base_module in THIRD_PARTY_MODULES:
            result['third_party'].append(line)
        else:
            result['local'].append(line)
    return result


def sort_imports(import_lines):
    categorized = categorize_imports(import_lines)
    result = []
    for group in ['stdlib', 'third_party', 'local']:
        result.extend(sorted(categorized[group], key=lambda s: s.lower()))
    return result
